const FUCHOUZHE_LOGO_DATA_URI = 'data:image/png;base64,';

export function getFuchouzheMarkSvg(size = 24): string {
	return `<svg width="${size}" height="${size}" viewBox="0 0 512 512" fill="none" xmlns="http://www.w3.org/2000/svg" aria-hidden="true" focusable="false"><image href="${FUCHOUZHE_LOGO_DATA_URI}" width="512" height="512"/></svg>`;
}

export function getFuchouzheLockupSvg(width = 160, height = 140): string {
	return `<svg width="${width}" height="${height}" viewBox="0 0 160 140" fill="none" xmlns="http://www.w3.org/2000/svg" aria-hidden="true" focusable="false">
		<image href="${FUCHOUZHE_LOGO_DATA_URI}" x="48" y="10" width="64" height="64"/>
		<text x="80" y="96" text-anchor="middle" font-size="18" font-weight="600" fill="#F4B63F" font-family="-apple-system, BlinkMacSystemFont, 'Segoe UI', 'PingFang SC', sans-serif" letter-spacing="4">富酬者</text>
		<text x="80" y="118" text-anchor="middle" font-size="11" font-weight="400" fill="#D9972F" font-family="-apple-system, BlinkMacSystemFont, 'Segoe UI', sans-serif" letter-spacing="8">AI</text>
	</svg>`;
}
